function MultiPotTimer() {
  const [timers, setTimers] = React.useState([
    {id:1,label:'Pasta',seconds:600,total:600,running:false},
    {id:2,label:'Rice',seconds:900,total:900,running:false}
  ]);

  React.useEffect(()=>{
    const id = setInterval(()=>{
      setTimers(prev=>prev.map(t=>{
        if (!t.running || t.seconds<=0) return t;
        const s = t.seconds-1;
        if (s===0) {
          const audio = new Audio('https://actions.google.com/sounds/v1/alarms/beep_short.ogg');
          audio.play().catch(()=>{});
        }
        return {...t,seconds:s};
      }));
    },1000);
    return ()=>clearInterval(id);
  },[]);

  const toggle = (id)=>setTimers(prev=>prev.map(t=>t.id===id?{...t,running:!t.running}:t));
  const reset = (id,total)=>setTimers(prev=>prev.map(t=>t.id===id?{...t,seconds:total,running:false}:t));
  const add = ()=>setTimers([...timers,{id:Date.now(),label:'New',seconds:300,total:300,running:false}]);
  const remove = (id)=>setTimers(timers.filter(t=>t.id!==id));

  const fmt = (s)=>`${String(Math.floor(s/60)).padStart(2,'0')}:${String(s%60).padStart(2,'0')}`;

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <span style={{fontSize:18,fontWeight:700}}>Kitchen Timers</span>
        <button onClick={add}
          style={{padding:'6px 12px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          + Add
        </button>
      </div>
      <div style={{flex:1,overflow:'auto',display:'flex',flexDirection:'column',gap:8}}>
        {timers.map(t=> (
          <div key={t.id} style={{padding:12,background:'#f5f5f5',borderRadius:10}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:6}}>
              <input value={t.label} onChange={e=>setTimers(prev=>prev.map(x=>x.id===t.id?{...x,label:e.target.value}:x))}
                style={{background:'transparent',border:'none',fontSize:14,fontWeight:600,width:100}}/>
              <button onClick={()=>remove(t.id)} style={{background:'none',border:'none',color:'#FF3B30',cursor:'pointer'}}>×</button>
            </div>
            <div style={{display:'flex',alignItems:'center',gap:10}}>
              <div style={{fontSize:28,fontVariantNumeric:'tabular-nums',fontWeight:200,flex:1,color:t.seconds===0?'#FF3B30':'#000'}}>
                {fmt(t.seconds)}
              </div>
              <button onClick={()=>toggle(t.id)}
                style={{padding:'6px 14px',borderRadius:8,border:'none',background:t.running?'#FF3B30':'#34C759',color:'#fff',cursor:'pointer',fontSize:13}}>
                {t.running?'Pause':'Start'}
              </button>
              <button onClick={()=>reset(t.id,t.total)}
                style={{padding:'6px 12px',borderRadius:8,border:'1px solid #ccc',background:'#fff',cursor:'pointer',fontSize:13}}>
                Reset
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<MultiPotTimer/>);
